namespace sv_aefc91fc3aff4b038d628df779594fa7.Client.Models;

public sealed record StatusUpdate(DateTime Timestamp, string Status, string Location);

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTime EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

using sv_aefc91fc3aff4b038d628df779594fa7.Client.Models;

namespace sv_aefc91fc3aff4b038d628df779594fa7.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_aefc91fc3aff4b038d628df779594fa7.Client.Models;
using sv_aefc91fc3aff4b038d628df779594fa7.Client.Services;

namespace sv_aefc91fc3aff4b038d628df779594fa7.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Memphis, TN",
            EstimatedDelivery: new DateTime(2026, 5, 25, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 20, 8, 0, 0, DateTimeKind.Utc), "Picked Up", "New York, NY"),
                new(new DateTime(2026, 5, 21, 14, 30, 0, DateTimeKind.Utc), "In Transit", "Philadelphia, PA"),
                new(new DateTime(2026, 5, 22, 6, 15, 0, DateTimeKind.Utc), "In Transit", "Memphis, TN"),
            }),
        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTime(2026, 5, 21, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 18, 9, 0, 0, DateTimeKind.Utc), "Picked Up", "Seattle, WA"),
                new(new DateTime(2026, 5, 19, 11, 0, 0, DateTimeKind.Utc), "In Transit", "Portland, OR"),
                new(new DateTime(2026, 5, 20, 16, 45, 0, DateTimeKind.Utc), "Out for Delivery", "San Francisco, CA"),
                new(new DateTime(2026, 5, 21, 10, 30, 0, DateTimeKind.Utc), "Delivered", "San Francisco, CA"),
            }),
        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTime(2026, 5, 28, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTime(2026, 5, 22, 7, 0, 0, DateTimeKind.Utc), "Order Placed", "Chicago, IL"),
            }),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_aefc91fc3aff4b038d628df779594fa7.Client.Models
@using sv_aefc91fc3aff4b038d628df779594fa7.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_error is not null)
{
    <div class="error-message">
        <p>@_error</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <table>
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Status</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Status</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _error;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _error = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _error = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

