using System.Net.Http.Json;
using sv_aefc91fc3aff4b038d628df779594fa7.Client.Models;

namespace sv_aefc91fc3aff4b038d628df779594fa7.Client.Services.Wasm;

public sealed class WasmShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public WasmShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

